#ifdef __cplusplus
extern "C" {
#endif

#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./kernel/kernel_cpu.h"

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    long bx;
    fp a2 = (fp)2.0 * par.alpha * par.alpha;

    omp_set_num_threads(dim.cores_arg);

#pragma omp parallel for private(bx) schedule(static)
    for (bx = 0; bx < dim.number_boxes; bx++) {
        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
        fp qB_shared[NUMBER_PAR_PER_BOX];

        int i, j, k;
        int first_i = (int)box[bx].offset;

        for (i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            rA_shared[i] = rv[first_i + i];
        }

        for (k = 0; k < (1 + box[bx].nn); k++) {
            int pointer;
            int first_j;

            if (k == 0) {
                pointer = (int)bx;
            } else {
                pointer = box[bx].nei[k - 1].number;
            }

            first_j = (int)box[pointer].offset;

            for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                rB_shared[j] = rv[first_j + j];
                qB_shared[j] = qv[first_j + j];
            }

            for (i = 0; i < NUMBER_PAR_PER_BOX; i++) {
                for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2;
                    fp u2;
                    fp vij;
                    fp fs;
                    fp fxij;
                    fp fyij;
                    fp fzij;
                    THREE_VECTOR d;

                    r2 = rA_shared[i].v + rB_shared[j].v - DOT(rA_shared[i], rB_shared[j]);
                    u2 = a2 * r2;
                    vij = exp(-u2);
                    fs = (fp)2.0 * vij;

                    d.x = rA_shared[i].x - rB_shared[j].x;
                    fxij = fs * d.x;
                    d.y = rA_shared[i].y - rB_shared[j].y;
                    fyij = fs * d.y;
                    d.z = rA_shared[i].z - rB_shared[j].z;
                    fzij = fs * d.z;

                    fv[first_i + i].v += qB_shared[j] * vij;
                    fv[first_i + i].x += qB_shared[j] * fxij;
                    fv[first_i + i].y += qB_shared[j] * fyij;
                    fv[first_i + i].z += qB_shared[j] * fzij;
                }
            }
        }
    }
}

#ifdef __cplusplus
}
#endif
